  /* Reset styles, usage recommended by LeafyGreen. */
  *,
  *:before,
  *:after {
    box-sizing: border-box;
  }
`;

export const bodyStyles = css`
  font-family: ${fontFamilies.default};
  font-size: ${BaseFontSize.Body1}px;
  margin: 0;
`;

