  play: async ({ canvas, userEvent }) => {
    await userEvent.click(canvas.getByText('Delete'));
    await expect(await canvas.findByText('Are you sure you want to delete this item?')).toBeVisible();
    await expect(canvas.getByRole('button', { name: /yes/i })).toBeVisible();
    await expect(canvas.getByRole('button', { name: /cancel/i })).toBeVisible();
